import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
// ... остальные импорты

export const SignInForm = () => {
  const [action, setAction] = useState('Sign in');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [login, setLogin] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState('');

  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setMessage('');

    try {
      const url = action === 'Sign in' 
        ? 'http://localhost:8080/api/auth/login'
        : 'http://localhost:8080/api/auth/register';

      const requestBody = action === 'Sign in'
        ? { loginOrEmail: email, password }
        : { login, email, password };

      const response = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(requestBody),
      });

      const data = await response.json();

      if (data.success) {
        setMessage(`✅ ${data.message}`);
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        localStorage.setItem('isAuthenticated', 'true');

        // Перенаправляем на главную страницу
        setTimeout(() => {
          navigate('/');
        }, 1000);
      } else {
        setMessage(`❌ ${data.message}`);
      }
    } catch (error) {
      setMessage(`❌ Ошибка сети: ${error.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  // Обработчик для перехода к восстановлению пароля
  const handleForgotPassword = () => {
    navigate('/forgot-password');
  };

  return (
    <div className="auth-page-container">
      <div className="sign-in-form-wrapper">
        <form className="sign-in-form" onSubmit={handleSubmit}>
          <div className='sign-in-name'>{action}</div>

          {/* Поле логина только для регистрации */}
          {action === 'Sign up' && (
            <div className="input-group">
              <input
                type="text"
                value={login}
                onChange={(e) => setLogin(e.target.value)}
                placeholder=" "
                required={action === 'Sign up'}
                disabled={isLoading}
              />
              <label>Login</label>
            </div>
          )}

          <div className="input-group">
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder=" "
              required
              disabled={isLoading}
            />
            <label>Email</label>
          </div>

          <div className="input-group">
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder=" "
              required
              disabled={isLoading}
              minLength="6"
            />
            <label>Password</label>
          </div>

          {message && (
            <div className={`message ${message.includes('✅') ? 'success' : 'error'}`}>
              {message}
            </div>
          )}

          <div className="separator">or continue with</div>

          <div className="social-login-icons">
            {/* Социальные кнопки */}
          </div>

          {/* Ссылка на восстановление пароля */}
          {action === 'Sign in' && (
            <Link 
              to="/forgot-password" 
              className="forgot-password"
              onClick={(e) => !isLoading && e.preventDefault()}
            >
              Forgot password?
            </Link>
          )}

          <div className="form-actions">
            {/* Кнопка Sign in */}
            <div 
              className={`action-button ${action === 'Sign in' ? 'active' : 'inactive'}`}
              onClick={action === 'Sign in' ? handleSubmit : () => !isLoading && setAction('Sign in')}
            >
              {action === 'Sign in' ? 
                <button type="submit" className="main-button" disabled={isLoading}>
                  {isLoading ? 'Loading...' : 'Sign in'}
                </button> : 
                <button type="button" className="secondary-button">
                  Sign in
                </button>
              }
            </div>

            {/* Кнопка Sign up */}
            <div 
              className={`action-button ${action === 'Sign up' ? 'active' : 'inactive'}`}
              onClick={action === 'Sign up' ? handleSubmit : () => !isLoading && setAction('Sign up')}
            >
              {action === 'Sign up' ? 
                <button type="submit" className="main-button" disabled={isLoading}>
                  {isLoading ? 'Loading...' : 'Sign up'}
                </button> : 
                <button type="button" className="secondary-button">
                  Sign up
                </button>
              }
            </div>
          </div>
        </form>
      </div>
    </div>
  );
};

export default SignInForm;
